async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Click Forester to get adjacent
  await click(840, 336);
  await page.waitForTimeout(3000);

  // Check distance
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const forester = s.nearby_entities?.find(e => e.name === 'Forester');
    return { pos: s.player_position, forester: forester ? { id: forester.id, dist: forester.distance } : null };
  });

  const st = JSON.parse(JSON.stringify(state));

  // Talk to Forester - call multiple times
  if (st.forester && st.forester.dist <= 3) {
    for (let i = 0; i < 5; i++) {
      const result = await page.evaluate((id) => window.__talkToNPC(id), st.forester.id);
      await page.waitForTimeout(1500);
    }
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const forester = s.nearby_entities?.find(e => e.name === 'Forester');
    const questPanel = document.getElementById('quest-button') ? document.getElementById('quest-button').style.display : 'not found';
    return { 
      pos: s.player_position,
      forester_dist: forester?.distance,
      quests_started: s.quests?.filter(q => q.started).map(q => q.name),
      quest_btn_visible: questPanel
    };
  });
  return JSON.stringify(finalState);
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Get forester click position
  const foresterInfo = await page.evaluate(() => {
    const s = window.__latestGameState;
    const f = s.nearby_entities?.find(e => e.name === 'Forester');
    return f ? { id: f.id, dist: f.distance, cx: f.click_x, cy: f.click_y } : null;
  });

  if (foresterInfo?.cx) {
    // Click on Forester position to walk up
    await click(foresterInfo.cx, foresterInfo.cy);
    await page.waitForTimeout(4000);
  }

  // Now talk regardless of distance (we should be very close)
  const id = foresterInfo?.id || '1-13246128';
  for (let i = 0; i < 6; i++) {
    await page.evaluate((npcId) => window.__talkToNPC(npcId), id);
    await page.waitForTimeout(1200);
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const forester = s.nearby_entities?.find(e => e.name === 'Forester');
    const btn = document.getElementById('quest-button');
    return { 
      pos: s.player_position,
      forester_dist: forester?.distance,
      quests_started: s.quests?.filter(q => q.started).map(q => ({name: q.name, stage: q.stage})),
      quest_btn_display: btn ? window.getComputedStyle(btn).display : 'none'
    };
  });
  return JSON.stringify(finalState);
}

