async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Get fresh tree positions and chop them
  let logs = 1;

  for (let round = 0; round < 4; round++) {
    const trees = await page.evaluate(() => {
      const s = window.__latestGameState;
      return s.nearby_entities?.filter(e => e.name === 'Oak' && e.on_screen && e.click_x).slice(0, 3).map(e => ({
        cx: e.click_x, cy: e.click_y, dist: e.distance
      }));
    });

    if (trees && trees.length > 0) {
      // Click nearest tree
      await click(trees[0].cx, trees[0].cy);
      await page.waitForTimeout(5000);

      const inv = await page.evaluate(() => {
        const s = window.__latestGameState;
        const logItem = s.inventory?.find(i => i.key === 'logs');
        return { count: logItem?.count || 0, inventory: s.inventory };
      });
      logs = inv.count;
    }
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {
      pos: s.player_position,
      inventory: s.inventory,
      foresting_stage: s.quests?.find(q => q.key === 'foresting')?.stage
    };
  });
  return JSON.stringify(finalState);
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Chop trees repeatedly until we have 10 logs
  for (let round = 0; round < 10; round++) {
    const trees = await page.evaluate(() => {
      const s = window.__latestGameState;
      return s.nearby_entities?.filter(e => e.name === 'Oak' && e.on_screen && e.click_x).slice(0, 2).map(e => ({
        cx: e.click_x, cy: e.click_y, dist: e.distance
      }));
    });

    if (trees && trees.length > 0) {
      await click(trees[0].cx, trees[0].cy);
      await page.waitForTimeout(5000);
    }

    const logCount = await page.evaluate(() => {
      const s = window.__latestGameState;
      return s.inventory?.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) || 0;
    });

    if (logCount >= 10) break;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const logCount = s.inventory?.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) || 0;
    return {
      pos: s.player_position,
      logs: logCount,
      inventory: s.inventory,
      foresting_stage: s.quests?.find(q => q.key === 'foresting')?.stage
    };
  });
  return JSON.stringify(finalState);
}

async (page) => {
