async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Find Forester and walk to them
  const forester = await page.evaluate(() => {
    const s = window.__latestGameState;
    const f = s.nearby_entities?.find(e => e.name === 'Forester');
    return f ? { id: f.id, dist: f.distance, cx: f.click_x, cy: f.click_y, on_screen: f.on_screen } : null;
  });

  if (forester?.on_screen && forester.cx) {
    await click(forester.cx, forester.cy);
    await page.waitForTimeout(3000);
  }

  // Talk to Forester to turn in logs
  const foresterId = forester?.id || '1-13246128';
  for (let i = 0; i < 6; i++) {
    await page.evaluate((id) => window.__talkToNPC(id), foresterId);
    await page.waitForTimeout(1200);
  }

  // Click quest button if visible
  await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn && window.getComputedStyle(btn).display !== 'none') btn.click();
  });
  await page.waitForTimeout(1000);

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    const logCount = s.inventory?.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) || 0;
    const q = s.quests?.find(q => q.key === 'foresting');
    return { pos: s.player_position, logs: logCount, quest: q ? { stage: q.stage, started: q.started, finished: q.finished } : null };
  });
  return JSON.stringify(finalState);
}

