    // Head northeast
    await click(900, 100);
    await page.waitForTimeout(4000);
  }

  // Re-check position
  forester = await page.evaluate(() => {
    const s = window.__latestGameState;
    const f = s.nearby_entities?.find(e => e.name === 'Forester');
    return f ? { id: f.id, dist: f.distance, cx: f.click_x, cy: f.click_y, on_screen: f.on_screen } : null;
  });

