      attackStyle: player.attackStyle,
      strengthLevel: strength,
      skillsKeys: skills ? Object.keys(skills) : [],
      playerKeys: Object.keys(player).filter(k => k.toLowerCase().includes('skill') || k.toLowerCase().includes('strength') || k.toLowerCase().includes('level'))
    };
  });
  return JSON.stringify(result);
}

