      nearest_mob: s?.nearest_mob
    };
  });
  console.log('State:', JSON.stringify(state));

  // Attack nearest crab
  const mob = state?.nearest_mob || (state?.crabs?.[0]);
  if (mob?.click_x && mob?.click_y) {
