async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  const getState = () => page.evaluate(() => {
    const s = window.__latestGameState;
    const player = window.game?.player;
    const str = Object.values(player?.skills || {}).find(sk => sk?.name === 'Strength');
    const items = s?.nearby_entities?.filter(e => e.type === 4); // item drops
    return {
      pos: s?.player_position,
      hp: s?.player_stats?.hp,
      max_hp: s?.player_stats?.max_hp,
      str_level: str?.level,
      str_exp: str?.experience,
      level: s?.player_stats?.level,
      mobs: s?.nearby_entities?.filter(e => e.type === 3 && e.on_screen).slice(0, 3).map(e => ({
        name: e.name, cx: e.click_x, cy: e.click_y, dist: e.distance, hp: e.hp
      })),
      items: items?.map(e => ({ name: e.name, cx: e.click_x, cy: e.click_y, dist: e.distance }))
    };
  });

  for (let i = 0; i < 8; i++) {
    const st = await getState();

    // Heal if low
    if (st.hp < st.max_hp * 0.4) {
      console.log('HP low, retreating');
      await click(180, 400); // move west away from mobs
      await page.waitForTimeout(5000);
      continue;
    }

    // Pick up any item drops first
    if (st.items?.length > 0) {
      const item = st.items[0];
      console.log('Item drop!', item.name);
      await click(item.cx, item.cy);
      await page.waitForTimeout(2000);
      continue;
    }

    // Prefer crabs, else attack any mob
    const crabs = st.mobs?.filter(e => e.name === 'Crab');
    const target = (crabs?.length > 0 ? crabs[0] : st.mobs?.[0]);

    if (target?.cx && target?.cy) {
      await click(target.cx, target.cy);
      await page.waitForTimeout(5000);
    } else {
      // Move west toward Bubba/hammer area (121, 231)
      await click(180, 400);
      await page.waitForTimeout(3000);
    }
  }

  const final = await getState();
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify(final);
}

