async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  const getState = () => page.evaluate(() => {
    const gs = window.__latestGameState;
    const str = Object.values(window.game?.player?.skills || {}).find(s => s.name === 'Strength');
    return {
      pos: gs?.player_position,
      hp: gs?.player_stats?.hp,
      max_hp: gs?.player_stats?.max_hp,
      str_level: str?.level,
      str_xp: str?.experience,
      mobs: (gs?.nearby_entities || []).filter(e => e.type === 3 && e.on_screen).slice(0, 3).map(e => ({
        name: e.name, dist: e.distance, cx: e.click_x, cy: e.click_y
      })),
      items: (gs?.nearby_entities || []).filter(e => e.type === 4 && e.on_screen).slice(0, 2).map(e => ({
        name: e.name, cx: e.click_x, cy: e.click_y
      }))
    };
  });

  // Grind loop - 20 iterations
  for (let i = 0; i < 20; i++) {
    const s = await getState();

    // Heal if low
    if (s.hp < s.max_hp * 0.35) {
      await click(180, 360);
      await page.waitForTimeout(8000);
      continue;
    }

    // Pick up items
    if (s.items?.length > 0) {
      await click(s.items[0].cx, s.items[0].cy);
      await page.waitForTimeout(1500);
      continue;
    }

    // Attack nearest mob
    if (s.mobs?.length > 0) {
      await click(s.mobs[0].cx, s.mobs[0].cy);
      await page.waitForTimeout(5000);
    } else {
      // Walk around to find mobs
      await click(700 + Math.random() * 200, 300 + Math.random() * 150);
      await page.waitForTimeout(3000);
    }

    if (i % 5 === 0) console.log(`Step ${i}: str=${s.str_level}(${s.str_xp}xp) hp=${s.hp}/${s.max_hp} pos=${JSON.stringify(s.pos)}`);
    if (s.str_level >= 10) { console.log('Reached Strength 10!'); break; }
  }

  const final = await getState();
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({ str: final.str_level, xp: final.str_xp, hp: final.hp, pos: final.pos });
}

