async (page) => {
  // Click soldier to walk adjacent
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, { x: 744, y: 384 });
  await page.waitForTimeout(2000);

  const s = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const soldier = (gs?.nearby_entities || []).find(e => e.name === 'Dying Soldier');
    return { pos: gs?.player_position, hp: gs?.player_stats?.hp,
      soldier: soldier ? {id: soldier.id, dist: soldier.distance} : null };
  });

  if (!s.soldier || s.soldier.dist > 2) return JSON.stringify({error: 'not adjacent', s});

  // Talk to soldier - call 6 times with observation between
  const soldierID = s.soldier.id || '1-20057275';
  const results = [];
  for (let i = 0; i < 7; i++) {
    const r = await page.evaluate((id) => window.__talkToNPC(id), soldierID);
    await page.waitForTimeout(1500);
    const st = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const quest = (gs?.quests || []).find(q => q.key === 'desertquest');
      const btnVisible = !!document.querySelector('#quest-button') && window.getComputedStyle(document.querySelector('#quest-button')).display !== 'none';
      return { hp: gs?.player_stats?.hp, quest: quest ? {started: quest.started, stage: quest.stage} : null, questBtnVisible: btnVisible };
    });
    results.push({ i, talkResult: r, state: st });
    if (st.questBtnVisible) break;
  }
  return JSON.stringify({ pos: s.pos, results });
}

